#define BLOCK_SIZE 16

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i = get_local_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Process upper triangle of diagonal block
    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + i) * size + offset + k] * a[(offset + k) * size + offset + j];
        }
        a[(offset + i) * size + offset + j] -= sum;
    }

    // Compute reciprocal of diagonal element
    float diag_inv = 1.0f / a[(offset + i) * size + offset + i];

    // Process lower triangle of diagonal block
    for (j = i + 1; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + j) * size + offset + k] * a[(offset + k) * size + offset + i];
        }
        a[(offset + j) * size + offset + i] = (a[(offset + j) * size + offset + i] - sum) * diag_inv;
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_bottom,
                          const int size, const int offset)
{
    int idx = get_local_id(0);
    int i, j, k, i_global, j_global;
    float sum;

    int chunks_in_inter_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;
    int chunk_idx = idx / BLOCK_SIZE;
    int part = idx >= BLOCK_SIZE * chunks_in_inter_row ? 1 : 0;

    if (part == 0) {
        // Right perimeter blocks
        if (chunk_idx >= chunks_in_inter_row) return;

        i_global = offset;
        j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        // Load temp from diagonal block
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_top[i * BLOCK_SIZE + j] = a[(i + offset) * size + offset + j];
            }
        }

        // Update right perimeter
        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += temp_top[BLOCK_SIZE * i + k] * a[(i_global + k) * size + j_global + j];
                }
                a[(i_global + i) * size + j_global + j] -= sum;
            }
        }
    } else {
        // Bottom perimeter blocks
        chunk_idx = idx - BLOCK_SIZE * chunks_in_inter_row;
        if (chunk_idx >= chunks_in_inter_row) return;

        j_global = offset;
        i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        // Load temp from diagonal block
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_top[i * BLOCK_SIZE + j] = a[(i + offset) * size + offset + j];
            }
        }

        // Update bottom perimeter
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[(i_global + i) * size + j_global + k] * temp_top[BLOCK_SIZE * k + j];
                }
                a[(i_global + i) * size + j_global + j] = (a[(i_global + i) * size + j_global + j] - sum) / a[(offset + j) * size + offset + j];
            }
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left,
                         const int size, const int offset)
{
    int idx_x = get_local_id(0);
    int idx_y = get_local_id(1);
    int i, j, k, i_global, j_global;
    float sum[BLOCK_SIZE];

    int chunks_in_inter_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx_x >= chunks_in_inter_row || idx_y >= chunks_in_inter_row) return;

    i_global = offset + BLOCK_SIZE * (1 + idx_y);
    j_global = offset + BLOCK_SIZE * (1 + idx_x);

    // Initialize sum array
    for (j = 0; j < BLOCK_SIZE; j++) {
        sum[j] = 0.0f;
    }

    // Load temp arrays
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[(i + offset) * size + j_global + j];
            temp_left[i * BLOCK_SIZE + j] = a[(i + i_global) * size + offset + j];
        }
    }

    // Compute sum accumulation
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (k = 0; k < BLOCK_SIZE; k++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += temp_left[BLOCK_SIZE * i + k] * temp_top[BLOCK_SIZE * k + j];
            }
        }
    }

    // Update internal block
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            a[(i_global + i) * size + j_global + j] -= sum[j];
        }
    }
}
